class AuctionSystem:
    def __init__(self):
        self.items = {}

    def _find(self, itemId, userId):
        lst = self.items.get(itemId, [])
        for i, (u, _a) in enumerate(lst):
            if u == userId:
                return i
        return -1

    def addBid(self, userId, itemId, bidAmount):
        lst = self.items.setdefault(itemId, [])
        idx = self._find(itemId, userId)
        if idx >= 0:
            lst[idx] = [userId, bidAmount]
        else:
            lst.append([userId, bidAmount])

    def updateBid(self, userId, itemId, newAmount):
        idx = self._find(itemId, userId)
        self.items[itemId][idx] = [userId, newAmount]

    def removeBid(self, userId, itemId):
        idx = self._find(itemId, userId)
        del self.items[itemId][idx]

    def getHighestBidder(self, itemId):
        lst = self.items.get(itemId, [])
        if not lst:
            return -1
        best = max(lst, key=lambda ua: (ua[1], ua[0]))
        return best[0]

