class AuctionSystem:
    def __init__(self):
        self.bids = {}

    def addBid(self, userId, itemId, bidAmount):
        self.bids.setdefault(itemId, {})[userId] = bidAmount

    def updateBid(self, userId, itemId, newAmount):
        self.bids[itemId][userId] = newAmount

    def removeBid(self, userId, itemId):
        del self.bids[itemId][userId]

    def getHighestBidder(self, itemId):
        item_bids = self.bids.get(itemId)
        if not item_bids:
            return -1
        best_user = None
        best_amount = None
        for userId, amount in item_bids.items():
            if best_amount is None or amount > best_amount or (amount == best_amount and userId > best_user):
                best_amount = amount
                best_user = userId
        return best_user

