class AuctionSystem {
    constructor() {
        this.bids = new Map();
    }
    addBid(userId, itemId, bidAmount) {
        if (!this.bids.has(itemId)) this.bids.set(itemId, new Map());
        this.bids.get(itemId).set(userId, bidAmount);
    }
    updateBid(userId, itemId, newAmount) {
        this.bids.get(itemId).set(userId, newAmount);
    }
    removeBid(userId, itemId) {
        this.bids.get(itemId).delete(userId);
    }
    getHighestBidder(itemId) {
        const itemBids = this.bids.get(itemId);
        if (!itemBids || itemBids.size === 0) return -1;
        let bestUser = null;
        let bestAmount = null;
        for (const [userId, amount] of itemBids) {
            if (bestAmount === null || amount > bestAmount || (amount === bestAmount && userId > bestUser)) {
                bestAmount = amount;
                bestUser = userId;
            }
        }
        return bestUser;
    }
}
